import { Footer } from 'components';
import { NextComponentType } from 'next';
import { ApolloPageContext } from 'next-with-apollo';
import dynamic from 'next/dynamic';
import React from 'react';

import { Layout as LayoutGQL, LayoutVariables } from './__generated__/Layout';
import { queryLayout } from './graphql';
import { InitProps, Props } from './props';

const Header = dynamic(() => import('./libs/Header'));

export const Layout: NextComponentType<ApolloPageContext, InitProps, Props> = (props: Props) => {
  console.log(props);
  return (
    <div className="d-flex flex-column" css={{ minHeight: '100vh' }}>
      <Header />
      {props.children}
      <Footer />
    </div>
  );
};

Layout.getInitialProps = async (ctx) => {
  const lang = ctx.req?.headers?.cookie?.match(/(kk-Cyrl-KZ|ru-RU)/)?.[0] || 'ru-RU';

  const data = await ctx.apolloClient.query<LayoutGQL, LayoutVariables>({
    query: queryLayout,
    variables: { locale: lang },
  });
  return { data };
};
